import axios from 'axios';
import Cookie from 'cookie-universal';

// ===== الإعدادات الأساسية =====
export const baseUrl = 'http://192.168.1.105:8000/api';

const cookie = Cookie();

// ===== إنشاء Axios Instance =====
const Axios = axios.create({
    baseURL: baseUrl,
    headers: {
        'Content-Type': 'application/json'
    }
});

// ===== Interceptor: إضافة Token تلقائياً =====
Axios.interceptors.request.use(
    (config) => {
        const token = cookie.get('educational-token');
        if (token) {
            config.headers.Authorization = `Bearer ${token}`;
        }
        return config;
    },
    (error) => Promise.reject(error)
);

// ===== تصدير Axios =====
export default Axios;

// ===== روابط الـ API (Endpoints) =====

// Authentication
export const REGISTER = 'register';
export const LOGIN = 'login';
export const LOGOUT = 'logout';
export const USER = 'user';

// Courses
export const COURSES = 'courses';
export const COURSES_FEATURED = 'courses/featured';
export const COURSE_BY_ID = 'courses'; // courses/{id}

// Admin
export const ADMIN_COURSES = 'admin/courses';
